	"github.com/stretchr/testify/require"
)

// loopEndExitReason scans a JSONL EventSink buffer and returns the
// exit_reason field of the loop.end event. Empty string when the event is
// absent or the field is unset.
func loopEndExitReason(t *testing.T, sink *bytes.Buffer) string {
	t.Helper()
	for _, line := range bytes.Split(bytes.TrimSpace(sink.Bytes()), []byte("\n")) {
		if len(line) == 0 {
			continue
		}
		var entry map[string]any
		if err := json.Unmarshal(line, &entry); err != nil {
			continue
		}
		if entry["type"] != "loop.end" {
			continue
		}
		data, _ := entry["data"].(map[string]any)
		if data == nil {
			return ""
		}
		s, _ := data["exit_reason"].(string)
		return s
	}
	return ""
}

// TestLoop_StaysAliveWithEmptyQueue covers ddx-dc157075 AC#2 + AC#6: when
// PollInterval > 0 and the queue is empty, the loop sleeps and rescans
// rather than returning. After N empty polls the queue refills with a fresh
// ready bead and the loop must pick it up. Without the attempted-map reset
// on the no-candidate path, this would hang forever once each currently-
// ready bead has been attempted once.
func TestLoop_StaysAliveWithEmptyQueue(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	// Close the seeded beads so the queue starts empty.
	require.NoError(t, store.CloseWithEvidence(first.ID, "seed", "seed"))
	require.NoError(t, store.CloseWithEvidence("ddx-0002", "seed", "seed"))

	var execCount int32
	var sink bytes.Buffer
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			atomic.AddInt32(&execCount, 1)
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-stay",
				ResultRev: "abc1234",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Drop a fresh ready bead onto the queue after a short delay so the
	// loop has to survive at least one empty poll first.
	go func() {
		time.Sleep(75 * time.Millisecond)
		_ = store.Create(&bead.Bead{ID: "ddx-late", Title: "late arrival", Priority: 0})
	}()

	// Cancel the loop once we've seen the late bead executed.
	go func() {
		deadline := time.Now().Add(2 * time.Second)
		for time.Now().Before(deadline) {
			if atomic.LoadInt32(&execCount) >= 1 {
				cancel()
				return
			}
			time.Sleep(10 * time.Millisecond)
		}
		cancel()
	}()

	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		PollInterval: 25 * time.Millisecond,
		EventSink:    &sink,
		SessionID:    "sess-stay",
	})
	// ctx.Cancel surfaces as a non-nil err; the loop must still have
	// stayed alive long enough to pick up the late bead.
	if err != nil {
		require.ErrorIs(t, err, context.Canceled)
	}
	require.NotNil(t, result)
	assert.GreaterOrEqual(t, int32(1), atomic.LoadInt32(&execCount), "executor should have run at least once on the late bead")
	assert.Equal(t, 1, result.Successes, "the late bead should have been picked up after multiple empty polls")
}

// TestLoop_PreflightRejectionContinues covers ddx-dc157075 AC#3 + AC#6:
// when RoutePreflight rejects one bead, the loop must continue to the next
// candidate rather than abandoning the whole queue.
func TestLoop_PreflightRejectionContinues(t *testing.T) {
	inner, first, second := newExecuteLoopTestStore(t)
	store := &claimCountingStore{Store: inner}

	var executed []string
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			executed = append(executed, beadID)
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-pre",
				ResultRev: "deadbeef",
			}, nil
		}),
	}

	// Fail preflight only for the first ready bead. The second must still
	// be claimed and executed in the same Run().
	preflight := func(ctx context.Context, harness, model string) error {
		// The loop calls preflight per candidate; toggle by current store
		// state. ReadyExecution returns first then second.
		ready, _ := inner.ReadyExecution()
		if len(ready) > 0 && ready[0].ID == first.ID {
			return agentlib.ErrHarnessModelIncompatible{
				Harness: harness, Model: model,
				SupportedModels: []string{"other-model"},
			}
		}
		return nil
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker", Harness: "claude", Model: "gpt-5"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		// PollInterval=0 + Once=false: drain-and-exit. Both ready beads
		// should be visited in this single Run().
		RoutePreflight: preflight,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	// The sibling bead must have been executed despite the first bead's
	// preflight rejection.
	require.Contains(t, executed, second.ID, "sibling bead must run despite preflight rejection on first")
	assert.NotContains(t, executed, first.ID, "rejected bead must not be claimed")
	assert.Equal(t, 1, result.Successes, "exactly one success (the sibling)")
	assert.Equal(t, 1, result.Failures, "exactly one preflight-rejection failure record")
}

// TestLoop_OnceFlagStillExits covers ddx-dc157075 AC#6 (back-compat):
// --once must continue to mean "process at most one ready bead, then exit".
func TestLoop_OnceFlagStillExits(t *testing.T) {
	store, _, _ := newExecuteLoopTestStore(t)
	var execCount int32
	var sink bytes.Buffer
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			atomic.AddInt32(&execCount, 1)
