// TestLoop_ExplicitPollZeroExits covers ddx-dc157075 AC#6 (back-compat):
// an operator who explicitly passes --poll-interval=0 must keep the legacy
// drain-and-exit semantics — drain the currently ready beads then exit.
func TestLoop_ExplicitPollZeroExits(t *testing.T) {
	store, _, _ := newExecuteLoopTestStore(t)
	require.NoError(t, store.CloseWithEvidence("ddx-0001", "seed", "seed"))
	require.NoError(t, store.CloseWithEvidence("ddx-0002", "seed", "seed"))

	var execCount int32
	var sink bytes.Buffer
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			atomic.AddInt32(&execCount, 1)
			return ExecuteBeadReport{BeadID: beadID, Status: ExecuteBeadStatusSuccess}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	start := time.Now()
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		// PollInterval=0 (default) + Once=false: drain-and-exit.
		EventSink: &sink,
	})
	elapsed := time.Since(start)
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, int32(0), atomic.LoadInt32(&execCount))
	assert.True(t, result.NoReadyWork, "result must report no_ready_work")
	assert.Less(t, elapsed, 1*time.Second, "PollInterval=0 must exit immediately on empty queue")
	assert.Equal(t, "explicit_poll_zero", loopEndExitReason(t, &sink))
}

// TestLoop_OnIdleFiresOnEmptyPoll covers ddx-dc157075 AC#5: when the loop
// sleeps on an empty poll the OnIdle callback must fire with idle=true and
// then idle=false on resume / exit.
func TestLoop_OnIdleFiresOnEmptyPoll(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	require.NoError(t, store.CloseWithEvidence(first.ID, "seed", "seed"))
	require.NoError(t, store.CloseWithEvidence("ddx-0002", "seed", "seed"))

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{}, nil
		}),
	}

	var idleSeq []bool
	var mu chan struct{} = make(chan struct{}, 8)
	onIdle := func(idle bool) {
		idleSeq = append(idleSeq, idle)
		select {
		case mu <- struct{}{}:
		default:
		}
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	go func() {
		// Wait for at least one idle=true callback to fire.
		<-mu
		// And cancel during the sleep so the loop unwinds.
		cancel()
